import{_ as a,o as t,c as o,ag as i}from"./chunks/framework.DEqXEGcv.js";const c=JSON.parse('{"title":"More Apps","description":"","frontmatter":{},"headers":[],"relativePath":"en/docs/guide/apps.md","filePath":"en/docs/guide/apps.md"}'),r={name:"en/docs/guide/apps.md"};function l(s,e,n,p,d,m){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="more-apps" tabindex="-1">More Apps <a class="header-anchor" href="#more-apps" aria-label="Permalink to &quot;More Apps&quot;">​</a></h1><p>Beyond the core file manager, Docker, and terminal, RDE comes with a rich set of built-in desktop applications.</p><h2 id="🎵-music-player" tabindex="-1">🎵 Music Player <a class="header-anchor" href="#🎵-music-player" aria-label="Permalink to &quot;🎵 Music Player&quot;">​</a></h2><p>A full-featured desktop music application:</p><ul><li><strong>Multiple display modes</strong>: Mini mode, window mode, wallpaper mode</li><li><strong>Lyrics display</strong>: LRC lyrics synchronized display</li><li><strong>Audio visualization</strong>: Spectrum bars, ring, kaleidoscope and more visual effects</li><li><strong>Playlists</strong>: Create and manage multiple playlists</li><li><strong>Supported formats</strong>: MP3, FLAC, WAV, OGG, AAC, etc.</li></ul><h2 id="🎬-video-player" tabindex="-1">🎬 Video Player <a class="header-anchor" href="#🎬-video-player" aria-label="Permalink to &quot;🎬 Video Player&quot;">​</a></h2><p>Multi-format desktop video player:</p><ul><li><strong>Wide format support</strong>: MP4, MKV, AVI, WebM, etc.</li><li><strong>Live transcoding</strong>: ffmpeg HLS transcoding for unsupported browser formats</li><li><strong>Subtitle support</strong>: Auto-load matching subtitle files</li><li><strong>Playback memory</strong>: Remember last playback position</li><li><strong>Speed control</strong>: 0.5x ~ 3x playback speed</li><li><strong>Picture-in-picture</strong>: Floating window playback</li><li><strong>File manager integration</strong>: Double-click video files to play directly</li></ul><h2 id="📸-photos" tabindex="-1">📸 Photos <a class="header-anchor" href="#📸-photos" aria-label="Permalink to &quot;📸 Photos&quot;">​</a></h2><p>A Synology/Immich-like indexed photo album system:</p><ul><li><strong>Auto indexing</strong>: Scan specified directories for photos</li><li><strong>Metadata extraction</strong>: EXIF/GPS information reading</li><li><strong>Thumbnail generation</strong>: Automatic multi-size thumbnail creation</li><li><strong>Album management</strong>: Create and organize albums</li><li><strong>Timeline view</strong>: Browse photos by date</li></ul><h2 id="🎮-retro-games" tabindex="-1">🎮 Retro Games <a class="header-anchor" href="#🎮-retro-games" aria-label="Permalink to &quot;🎮 Retro Games&quot;">​</a></h2><p>A pure frontend retro game emulator based on EmulatorJS (WebAssembly):</p><ul><li><strong>Supported platforms</strong>: NES, SNES, GBA, GBC, N64, PS1, NDS, Sega MD and 12 more classic platforms</li><li><strong>ROM management</strong>: Upload and manage game ROM files</li><li><strong>Gamepad support</strong>: Connect USB/Bluetooth gamepads</li><li><strong>Save states</strong>: Save/load at any time</li><li><strong>Pure frontend</strong>: No additional backend service required</li></ul><h2 id="📦-flatpak-apps" tabindex="-1">📦 Flatpak Apps <a class="header-anchor" href="#📦-flatpak-apps" aria-label="Permalink to &quot;📦 Flatpak Apps&quot;">​</a></h2><p>Run Linux desktop GUI applications in the browser:</p><ul><li>Browser GUI rendering via KasmVNC</li><li>Flatpak as the app source, universal across distributions</li><li>Multi-session concurrent support</li><li>App install/uninstall management</li></ul><h2 id="📊-system-monitor" tabindex="-1">📊 System Monitor <a class="header-anchor" href="#📊-system-monitor" aria-label="Permalink to &quot;📊 System Monitor&quot;">​</a></h2><p>Real-time system monitoring dashboard:</p><ul><li>CPU usage and load</li><li>Memory usage</li><li>Disk space and I/O</li><li>Network traffic</li></ul>',20)])])}const g=a(r,[["render",l]]);export{c as __pageData,g as default};
